section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/django-services.json",
  "type": "object",
  "title": "Django Services Layer",
  "required": [
    "service_name",
    "module_path",
    "kw_only",
    "type_hints_complete",
    "write_count",
    "atomic",
    "side_effects_on_commit",
    "tests_path"
  ],
  "additionalProperties": false,
  "properties": {
    "service_name": {
      "type": "string",
      "minLength": 1,
      "description": "entity_action name."
    },
    "module_path": {
      "type": "string",
      "minLength": 1,
      "description": "Dotted path apps.<app>.services."
    },
    "kw_only": {
      "type": "boolean",
      "description": "All args keyword-only."
    },
    "type_hints_complete": {
      "type": "boolean",
      "description": "Return + arg types declared."
    },
    "write_count": {
      "type": "integer",
      "description": "Number of writes performed."
    },
    "atomic": {
      "type": "boolean",
      "description": "Wrapped in @transaction.atomic."
    },
    "side_effects_on_commit": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Side effects dispatched via on_commit."
    },
    "tests_path": {
      "type": "string",
      "minLength": 1,
      "description": "Path to the service tests."
    }
  }
}
